  it("sums lines with no discount", () => {
    expect(orderTotalCents([{ unitCents: 500, qty: 2 }], 0)).toBe(1000);
  });

  it("rounds the discounted subtotal once, not per line", () => {
    // Two $5.00 lines, 10.06% off. Subtotal 1000c * 0.8994 = 899.4 -> 899 ($8.99).
    // Per-line rounding gives 450 + 450 = 900 ($9.00), the reported one-cent drift.
    const lines = [
      { unitCents: 500, qty: 1 },
      { unitCents: 500, qty: 1 },
    ];
    expect(orderTotalCents(lines, 10.06)).toBe(899);
  });
});

